"""Unit tests for the pressure vessel interlock controller."""

import unittest

from components.controller.controller import (
    controller_init,
    controller_step,
    controller_state_name,
)
from components.controller.controller import CONTROLLER_INPUT_NONE, CONTROLLER_INPUT_PRESSURE
from components.controller.controller import CONTROLLER_INPUT_DOOR_OPEN, CONTROLLER_INPUT_DOOR_CLOSED
from components.controller.controller import CONTROLLER_STATE_SAFE_VENT, CONTROLLER_STATE_PRESSURIZING
from components.controller.controller import CONTROLLER_STATE_HOLDING, CONTROLLER_STATE_RELIEVING


class TestControllerInit(unittest.TestCase):
    """Test controller initialization."""

    def test_boot_leaves_compressor_off_and_vent_open(self):
        """Boot leaves the compressor off and the vent open."""
        controller = {}
        output = controller_step(controller, {
            'kind': CONTROLLER_INPUT_NONE,
            'pressure_kpa': 0,
            'door_closed': False,
            'now_ms': 0,
        })
        self.assertFalse(output['compressor_on'])
        self.assertTrue(output['vent_open'])


class TestControllerBootState(unittest.TestCase):
    """Test controller stays in safe vent-open state until both sensors seen."""

    def test_stays_safe_until_both_sensors_valid(self):
        """The controller stays in the safe vent-open state until both door and pressure have been seen validly."""
        controller = {}

        # Only pressure, no door yet - should stay safe
        output = controller_step(controller, {
            'kind': CONTROLLER_INPUT_PRESSURE,
            'pressure_kpa': 35,
            'door_closed': False,
            'now_ms': 100,
        })
        self.assertFalse(output['compressor_on'])
        self.assertTrue(output['vent_open'])
        self.assertEqual(output['state'], CONTROLLER_STATE_SAFE_VENT)


class TestControllerLowPressure(unittest.TestCase):
    """Test controller with low pressure."""

    def test_door_closed_low_pressure_pressurizes(self):
        """With door closed and low pressure such as 35, the controller commands COMPRESSOR ON and VENT CLOSED."""
        controller = {}

        # First receive door closed
        output1 = controller_step(controller, {
            'kind': CONTROLLER_INPUT_DOOR_CLOSED,
            'pressure_kpa': 0,
            'door_closed': True,
            'now_ms': 100,
        })

        # Then receive low pressure
        output2 = controller_step(controller, {
            'kind': CONTROLLER_INPUT_PRESSURE,
            'pressure_kpa': 35,
            'door_closed': False,
            'now_ms': 200,
        })

        self.assertTrue(output2['compressor_on'])
        self.assertFalse(output2['vent_open'])
        self.assertEqual(output2['state'], CONTROLLER_STATE_PRESSURIZING)


class TestControllerHighPressure(unittest.TestCase):
    """Test controller with high pressure."""

    def test_door_closed_high_pressure_relieves(self):
        """With door closed and high pressure such as 65, the controller commands COMPRESSOR OFF and VENT OPEN."""
        controller = {}

        # First receive door closed
        output1 = controller_step(controller, {
            'kind': CONTROLLER_INPUT_DOOR_CLOSED,
            'pressure_kpa': 0,
            'door_closed': True,
            'now_ms': 100,
        })

        # Then receive high pressure
        output2 = controller_step(controller, {
            'kind': CONTROLLER_INPUT_PRESSURE,
            'pressure_kpa': 65,
            'door_closed': False,
            'now_ms': 200,
        })

        self.assertFalse(output2['compressor_on'])
        self.assertTrue(output2['vent_open'])
        self.assertEqual(output2['state'], CONTROLLER_STATE_RELIEVING)


class TestControllerInBand(unittest.TestCase):
    """Test controller behavior within the working band."""

    def test_in_band_preserves_previous_output(self):
        """In the 40..60 band, the controller preserves the previous safe output."""
        controller = {}

        # First pressurize (low pressure)
        output1 = controller_step(controller, {
            'kind': CONTROLLER_INPUT_DOOR_CLOSED,
            'pressure_kpa': 0,
            'door_closed': True,
            'now_ms': 100,
        })
        output2 = controller_step(controller, {
            'kind': CONTROLLER_INPUT_PRESSURE,
            'pressure_kpa': 35,
            'door_closed': False,
            'now_ms': 200,
        })

        self.assertTrue(output2['compressor_on'])
        self.assertFalse(output2['vent_open'])

        # Now move into band - should hold previous output
        output3 = controller_step(controller, {
            'kind': CONTROLLER_INPUT_PRESSURE,
            'pressure_kpa': 50,
            'door_closed': False,
            'now_ms': 300,
        })

        self.assertTrue(output3['compressor_on'])
        self.assertFalse(output3['vent_open'])
        self.assertEqual(output3['state'], CONTROLLER_STATE_HOLDING)


class TestControllerDoorOpen(unittest.TestCase):
    """Test controller behavior when door opens."""

    def test_door_open_forces_safe_vent(self):
        """A door-open event immediately forces the safe vent-open output."""
        controller = {}

        # First pressurize
        output1 = controller_step(controller, {
            'kind': CONTROLLER_INPUT_DOOR_CLOSED,
            'pressure_kpa': 0,
            'door_closed': True,
            'now_ms': 100,
        })
        output2 = controller_step(controller, {
            'kind': CONTROLLER_INPUT_PRESSURE,
            'pressure_kpa': 35,
            'door_closed': False,
            'now_ms': 200,
        })

        self.assertTrue(output2['compressor_on'])
        self.assertFalse(output2['vent_open'])

        # Now door opens - should force safe vent
        output3 = controller_step(controller, {
            'kind': CONTROLLER_INPUT_DOOR_OPEN,
            'pressure_kpa': 0,
            'door_closed': False,
            'now_ms': 300,
        })

        self.assertFalse(output3['compressor_on'])
        self.assertTrue(output3['vent_open'])
        self.assertEqual(output3['state'], CONTROLLER_STATE_SAFE_VENT)


class TestControllerNeverCompressorOnVentOpen(unittest.TestCase):
    """Test that controller never commands COMPRESSOR ON and VENT OPEN together."""

    def test_never_compressor_on_and_vent_open_together(self):
        """The controller never commands COMPRESSOR ON and VENT OPEN at the same time."""
        controller = {}

        # Test all states
        for pressure in [35, 50, 65]:
            output1 = controller_step(controller, {
                'kind': CONTROLLER_INPUT_DOOR_CLOSED,
                'pressure_kpa': 0,
                'door_closed': True,
                'now_ms': 100,
            })
            output2 = controller_step(controller, {
                'kind': CONTROLLER_INPUT_PRESSURE,
                'pressure_kpa': pressure,
                'door_closed': False,
                'now_ms': 200,
            })

            # Never both on at the same time
            self.assertFalse(
                output2['compressor_on'] and output2['vent_open'],
                f"Pressure {pressure}: compressor ON and vent OPEN together!"
            )


class TestControllerStateName(unittest.TestCase):
    """Test controller state name function."""

    def test_state_names_return_correct_strings(self):
        """All state names return the correct string representation."""
        self.assertEqual(controller_state_name(CONTROLLER_STATE_SAFE_VENT), "STATE SAFE_VENT")
        self.assertEqual(controller_state_name(CONTROLLER_STATE_PRESSURIZING), "STATE PRESSURIZING")
        self.assertEqual(controller_state_name(CONTROLLER_STATE_HOLDING), "STATE HOLDING")
        self.assertEqual(controller_state_name(CONTROLLER_STATE_RELIEVING), "STATE RELIEVING")


if __name__ == '__main__':
    unittest.main()

